package pkg;
    typedef enum bit [1:0] {
        CODE_NOOP = 2'd0,
        CODE_PASS = 2'd1,
        CODE_FAIL = 2'd2,
        CODE_DONE = 2'd3
    } status_code;
endpackage

interface my_if();
    pkg::status_code status;
    modport in  (input  status);
    modport out (output status);
endinterface
